import { initTRPC } from '@trpc/server';
import { CreateNodeHTTPServerOptions } from '@trpc/server/adapters/standalone';

const t = initTRPC.create();

const appRouter = t.router({
  countdown: t.procedure.subscription(async function* () {
    // Yield numbers from 3 down to 1 with 100ms delay
    for (let i = 3; i >= 1; i--) {
      yield i;
      await new Promise((resolve) => setTimeout(resolve, 100));
    }
  }),
});

export type AppRouter = typeof appRouter;

// Simple HTTP server for SSE subscriptions
const http = require('http');

const server = http.createServer(async (req, res) => {
  if (req.url === '/trpc') {
    // Set SSE headers
    res.writeHead(200, {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      'Connection': 'keep-alive',
    });

    // Create a simple SSE handler
    const generator = appRouter.countdown({ ctx: {} });

    try {
      for await (const value of generator) {
        res.write(`data: ${JSON.stringify({ data: value })}\n\n`);
      }
      res.write('data: [DONE]\n\n');
    } catch (error) {
      console.error('Subscription error:', error);
      res.write(`data: ${JSON.stringify({ error: 'Subscription error' })}\n\n`);
    } finally {
      res.end();
    }
  } else {
    res.writeHead(404);
    res.end('Not Found');
  }
});

const PORT = 3000;

server.listen(PORT, () => {
  console.log(`tRPC server running on http://localhost:${PORT}`);
});

